const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at);
const produkte = {};
for (const o of orders) {
  for (const li of (o.line_items || [])) {
    if (!produkte[li.title]) produkte[li.title] = { menge: 0, umsatz: 0 };
    produkte[li.title].menge += li.quantity;
    produkte[li.title].umsatz += parseFloat(li.price || 0) * li.quantity;
  }
}
const top = Object.entries(produkte)
  .sort((a, b) => b[1].umsatz - a[1].umsatz)
  .slice(0, 3)
  .map(([name, d], i) => (i + 1) + '. ' + name + ' (' + d.menge + ' verkauft, ' + d.umsatz.toFixed(0) + ' Umsatz)');
const topText = top.length ? top.join('\n') : '(noch keine Verkaeufe - erstelle Ads fuer die Nische allgemein)';

const prompt = 'Du bist Direct-Response-Werbetexter (Meta + TikTok Ads) fuer den Onlineshop "' + setup.SHOP_NAME + '" (Nische: ' + setup.SHOP_NISCHE + ').\n' +
  'Zielgruppe: ' + setup.ZIELGRUPPE + '\n\n' +
  'Top-Produkte der letzten 30 Tage:\n' + topText + '\n\n' +
  'Erstelle fuer das UMSATZSTAERKSTE Produkt das komplette Ad-Paket der Woche, auf Deutsch:\n\n' +
  '1. FUENF Werbe-Hooks (verschiedene Winkel: Schmerzpunkt, Neugier, Social Proof, Angebot, Kontrast/Mythos)\n' +
  '2. ZWEI TikTok/Reels UGC-Skripte (je 25-35s, Szene fuer Szene mit gesprochenem Text - klingen wie echte Kunden, nicht wie Werbung)\n' +
  '3. EINE Meta-Ad: Primary Text (AIDA, max 120 Woerter) + 3 Headlines (max 40 Zeichen) + Beschreibung\n' +
  '4. DREI Targeting-Ideen (Interessen/Verhalten fuer Meta, Kurzbegruendung)\n' +
  '5. EIN A/B-Test-Vorschlag fuer diese Woche (was testen, warum, Erfolgskriterium)\n\n' +
  'Antworte als sauberes HTML (h2/h3-Ueberschriften, Listen, kein <html>/<body>-Geruest, kein Markdown-Codeblock) - es wird direkt als E-Mail verschickt.';

return [{ json: { prompt } }];

const blocks = $json.content || [];
const html = (blocks.find(b => b.type === 'text') || {}).text || '';
const setup = $('⚙️ Setup').first().json;
return { json: {
  betreff: '🎯 Ad-Fabrik: Dein Werbe-Paket fuer diese Woche (' + setup.SHOP_NAME + ')',
  email_html: '<div style="font-family:sans-serif;max-width:640px;margin:0 auto;">' + html.replace(/```html|```/g, '') + '</div>'
}};
